val bottomNavItems = listOf(
    Screen.Home,
    Screen.Classes,
    Screen.Bus,
    Screen.AddEdit,
    Screen.Weather,
    Screen.Notifications
)

class MainActivity : ComponentActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        setContent {
            Combined_scheduleTheme {
