        val ollamaReachable = try {
            val conn = URL("http://localhost:11434").openConnection() as HttpURLConnection
            conn.connectTimeout = 2_000
            conn.requestMethod = "GET"
            conn.responseCode == 200
        } catch (e: Exception) {
            false
        }
