        val report = QualityReport("Accuracy – MP 4 due date", answer)

        // The due date is 2026-04-25; the model may reformat it
        report.assertContainsAnyOf("April 25", "Apr 25", "04-25", "2026-04-25", "25th")
        report.assertNoError()
        report.print()
    }

